class LFUCache {
    int cap, minFreq;
    unordered_map<int, pair<int,int>> kv;          // key -> {value, freq}
    unordered_map<int, list<int>> freqList;      // freq -> list of keys (LRU order)
    unordered_map<int, list<int>::iterator> pos;   // key -> iterator in freqList[freq]

    void touch(int key) {
        int f = kv[key].second;
        auto it = pos[key];
        freqList[f].erase(it);
        if (freqList[f].empty()) {
            freqList.erase(f);
            if (minFreq == f) ++minFreq;
        }
        ++kv[key].second;
        f = kv[key].second;
        freqList[f].push_back(key);
        pos[key] = prev(freqList[f].end());
    }

public:
    LFUCache(int capacity) : cap(capacity), minFreq(0) {}

    int get(int key) {
        if (!kv.count(key)) return -1;
        touch(key);
        return kv[key].first;
    }

    void put(int key, int value) {
        if (cap <= 0) return;
        if (kv.count(key)) {
            kv[key].first = value;
            touch(key);
            return;
        }
        if (kv.size() == cap) {
            int k = freqList[minFreq].front();
            kv.erase(k);
            pos.erase(k);
            freqList[minFreq].pop_front();
            if (freqList[minFreq].empty()) freqList.erase(minFreq);
        }
        kv[key] = {value, 1};
        freqList[1].push_back(key);
        pos[key] = prev(freqList[1].end());
        minFreq = 1;
    }
};
```
efficiency: HIGH
time complexity: O(1) average per operation
space complexity: O(capacity)
energy implications: LOW
explanation: Uses three hash maps and doubly-linked lists to maintain key-value pairs, frequency counts, and LRU order within each frequency. Each get/put touches a key in O(1) by moving it to the next frequency list. Eviction removes the front of the lowest-frequency list.

